/**
 * catalogue.ts
 *
 * Metadata catalogue for every overlay in the app. Render-free — used by
 * tooling (admin smoketest pages, doctrine checks, URL hydration, the
 * window manager's persistence layer). The OverlayController does NOT
 * iterate this catalogue; its render path is fully explicit.
 *
 * Generated by scripts/generate-overlay-controller.ts `catalogue` mode.
 */
import type { OverlayId } from "@/features/window-panels/registry/overlay-ids";

export interface OverlayCatalogueEntry {
  /** Human-readable label. Shown in tooling. */
  label: string;
  /** Singleton overlays reuse one slot; multi spawn fresh per dispatch. */
  instanceMode: "singleton" | "multi";
  /** True if the component renders a WindowPanel chrome. */
  isWindow: boolean;
}

